INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027bcce3c98b09417659c6', '喜欢的酒店，老牌风，有厚度。方便出行，出门右转即地铁站，去哪儿都很方便的。酒店的餐厅好吃，服务也相当到位的。', '["https://dimg04.c-ctrip.com/images/0233f12000en9tv2dD349_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000en9vai5EFED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000en9jl2a0CE8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000en9uvgfCFB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000en9miqdFFA0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000ena02ws4076_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000ena0ngsDD0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000ena1lmv4B06_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-02', '花园大床房', '大床房', '家庭亲子', 54, 0, 54, 7, '["交通便利性","餐饮设施","前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务'),
('68027bcce3c98b09417659c7', '这次广州行，爸爸极力推荐住花园酒店，真的超级满意。办理入住是一个外国小哥，特别的热情，还送了鲜花，中文也说的非常好！儿子最近热衷看老王的视频，一个劲的说小哥好像老王。酒店荣誉满满，有自己的博物馆可以预约参观。下次到广州来还会选择！', '["https://dimg04.c-ctrip.com/images/0235a12000dlert38C862_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000dlerrp0A264_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000dles3g6B491_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000dleqvsuB61A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000dlergu0B1AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000dles39v5755_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000dlerzfi490F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000dletad7DC66_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-05', '花园双床房', '双床房', '家庭亲子', 115, 0, 1, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027bcce3c98b09417659c8', '总体可以，设施比较老一些', '["https://dimg04.c-ctrip.com/images/0234j12000fcd059r06FA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-09-01', '花园大床房', '大床房', '独自旅行', 12, 0, 1, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027bcce3c98b09417659c9', '真的是很用心在服务的酒店，装修很美，设施很棒。
房间很舒服，宽敞干净', '["https://dimg04.c-ctrip.com/images/0230v12000etuu1a9AA35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000etutd0m665D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000etv07mgA3D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-19', '花园大床房', '大床房', '商务出差', 34, 0, 10, 6, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027bcce3c98b09417659ca', '经常来广州花园酒店接待合作伙伴，每次来都感觉很舒心，一进门有礼宾帮忙开门，并且主动和我打招呼，入住认识了 前厅部副经理 Lavinia吴灵伶，很热情地给我办入住，让我感受到温暖和体贴的服务，非常满意，五星好评', '["https://dimg04.c-ctrip.com/images/0232s12000f1uw0a8A2DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000f1v0u601BE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000f1uxsy0DB2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000f1v0fky4712_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000f1v2hoa0F5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000f1utn7114DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000f1v0u624386_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-08', '花园大床房', '大床房', '商务出差', 104, 0, 10, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027bcce3c98b09417659cb', '非常满意的一次住宿体验，酒店设施好，服务热情周到，免费升级客房并升级至30楼旋转餐厅享用早餐，非常感谢！酒店就在地铁淘金站旁边，出行非常方便，距机场也只有二三十分钟车程。总之，本次广州之行让我爱上了广州。', '["https://dimg04.c-ctrip.com/images/0236w12000dlg1b9kEF0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000dlg0iizB09E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000dlg0a8o359D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000dlg1b9m0EDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000dlg004t2A0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000dlg0a8q495E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-05', '花园双床房', '双床房', '家庭亲子', 102, 0, 7, 8, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027bd8e3c98b09417659cc', '酒店环境优美，房间整洁，已多次入住，这次还免费升级房间??', '["https://dimg04.c-ctrip.com/images/0235i12000ex0sxz847F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000ex0rq7oB0C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000ex0s1l98CB1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园大床房', '大床房', '商务出差', 29, 0, 1, 5, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027bd8e3c98b09417659cd', '花园酒店是我住过的最好的酒店之一，酒店内部环境非常养眼，服务也非常棒，非常满意！', '["https://dimg04.c-ctrip.com/images/0231r12000eub4wkq7E7F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000eub8q7j1DA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000euav5yt39CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000euay0i50DFE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000euav5yv169B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000euav5241261_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000eub8uudE6E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000eub0yljC261_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-20', '花园双床房', '双床房', '情侣出游', 40, 0, 49, 5, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027bd8e3c98b09417659ce', '服务很好，每个人都很热情，免费升级了一个套房，很安静很舒服，欢迎甜品很可爱，其实本来冲着美食酒店入住的，对餐食有点小小的失望，不过下次来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234t12000dt5l3zjC8F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000dt5tntmAD54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-28', '城央绿意大床房', '大床房', '朋友出游', 79, 0, 3, 7, '["前台服务","整体满意度","安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度'),
('68027bd8e3c98b09417659cf', '很不错，老牌五星级酒店标杆', '["https://dimg04.c-ctrip.com/images/0234a12000fadl54sDC63_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 13, 0, 2, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027bd8e3c98b09417659d0', '卫生干净   服务到位  还有博物馆参观。了解中外酒店史??', '["https://dimg04.c-ctrip.com/images/0236612000evwes92537C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-24', '花园大床房', '大床房', '其他', 30, 0, 5, 4, '["卫生状况","前台服务","客房服务"]'::jsonb, '卫生状况', '前台服务', '客房服务'),
('68027bd8e3c98b09417659d1', '谢谢花园酒店的接待，从一下车开始就收到了无微不至的关怀。前台的邓先生给我们安排了一间套房，还附赠了行政酒廊入场券和早餐券；房间宽敞明亮整洁，硬件设施也无可挑剔；在暴雨天气下，酒店的娱乐设施（后花园博物馆什么的应有尽有）和餐饮也足够满足需求。凌璇阁的餐饮环境服务也让人印象深刻，特别是有一位印度裔的服务员Carrie很贴心，中文也特别好。Thank you Carrie！岭南集团的酒店水准一直都让人很满意！', '["https://dimg04.c-ctrip.com/images/0234h12000dt9ldrn2326_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000dt8yqxq951B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000dt97mdzC449_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000dt9l6cx51F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000dt94xkhE35F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-28', '花园大床房', '大床房', '情侣出游', 203, 0, 18, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027bd8e3c98b09417659d2', '酒店环境一流，很多景观值得亲子打卡，参加活动也有小礼物赠送；前台服务到位，ann和cassie直接帮忙升级为红棉房并加赠早餐以及酒廊待遇一人份；餐饮方面有多个餐厅可供选择，美食多样、服务勤快。总之，在携程活动加持下酒店体验超预期，大赞！', '["https://dimg04.c-ctrip.com/images/0230c12000f9b4sgf72E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000f9b1tsb81A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000f9b5wswDA83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000f9b4mfb3A13_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-26', '花园双床房', '双床房', '家庭亲子', 118, 0, 2, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027bd8e3c98b09417659d3', '广州花园酒店，让我们非常惊艳！大堂依然大气、豪华，中西餐都让人极其享受。虽然是老牌五星酒店，各类设施维护保养极好，服务更是保持了五星水准！强烈推荐！', '["https://dimg04.c-ctrip.com/images/0236o12000do2nfbuC63F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000do2nwcwD440_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000do2of9v19D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000do2o1ymD7F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000do2on2b81A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000do2o0lr27C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000do2oc5aD319_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000do2p2c16A4E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000do2nfc311C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-13', '城央绿意大床房', '大床房', '商务出差', 74, 1, 7, 8, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027bd8e3c98b09417659d4', '到广州一如既往选择花园酒店入住，地铁和打车出行都很方便。前台帮忙升级了套房～宽敞很多住起来很舒服，设施一点点旧但齐全整洁。客务中心小杨也有主动了解体验反馈。
花园酒店真的经典，比起普通酒店好玩，岭南文化满满，这次有时间参观了四楼博物馆。瀑布餐厅早餐时间开到11点，不用早起赶时间??餐厅view很好！24h的健身房也很贴心！下次来有机会再试试桃园馆餐厅！', '["https://dimg04.c-ctrip.com/images/0236012000jlptwfgE650_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000jlpsm9x9B8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000jlpeed1E1C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000jlq5jyaA7C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000jlpzmu6CAC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '城央绿意大床房', '大床房', '朋友出游', 177, 0, 18, 9, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027bd8e3c98b09417659d5', '老牌酒店，情怀满满，还有多家超棒的餐厅，很值得一住。', '["https://dimg04.c-ctrip.com/images/0236v12000ey0mq9q18B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000ey0nqbmFFC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000ey0idiyE835_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000ey0isywF9A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000ey0grbgCCEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-30', '红棉大床套房', '套房', '家庭亲子', 26, 0, 7, 5, '["餐饮设施","整体满意度","性价比"]'::jsonb, '餐饮设施', '整体满意度', '性价比'),
('68027be3e3c98b09417659d6', '一走进大堂被震撼到了，金碧辉煌。酒店各环节的服务都很好，特别是我们的车刚停，门童立马过来开门、提箱，引导到前台办理入住。客房干净整洁，就是隔音不是很好，酒店位置交通便利，出行方便。', '["https://dimg04.c-ctrip.com/images/0201a12000doc614u8416_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231z12000dobt8na5FEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000doboa3gE46B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-14', '花园双床房', '双床房', '朋友出游', 90, 0, 27, 8, '["前台服务","交通便利性","安静程度"]'::jsonb, '前台服务', '交通便利性', '安静程度'),
('68027be3e3c98b09417659d7', '不愧是白金五星，房间干净整洁，维护得很好。服务一流，大堂穿bulinhbuling衣服小姐姐太给力了。环境特别好，早餐丰富，地理位置也方便', '["https://dimg04.c-ctrip.com/images/0232d12000e0yhuatC48B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000e0yll022FD2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-16', '花园双床房', '双床房', '朋友出游', 69, 0, 7, 8, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027be3e3c98b09417659d8', '房间安静舒适，整洁卫生，客务部小刘服务热情周到，客房服务员小王、Tina细心服务??????', '["https://dimg04.c-ctrip.com/images/0233l12000jb7pk2l058F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-25', '红棉大床套房', '套房', '家庭亲子', 46, 0, 4, 6, '["客房服务","安静程度","卫生状况"]'::jsonb, '客房服务', '安静程度', '卫生状况'),
